import { NextRequest, NextResponse } from 'next/server'
import { auth } from '@clerk/nextjs/server'
import { createAdminClient } from '@/lib/supabase'
import OpenAI from 'openai'
import { buildSystemPrompt, buildUserPrompt } from '@/lib/prompts'
import type { UserProfile } from '@/types/profile'


const FREE_MODEL = 'gpt-4o-mini'
const PRO_MODEL  = 'gpt-4.1'

export async function POST(req: NextRequest) {
  try {
    const openai  = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })
    const { userId } = await auth()
    if (!userId) {
      return NextResponse.json({ error: 'Unauthorised' }, { status: 401 })
    }

    const supabase = createAdminClient()

    // Fetch user + profile
    const { data: user, error: userError } = await supabase
      .from('users')
      .select('*, profiles(*)')
      .eq('clerk_id', userId)
      .single()

    if (userError || !user) {
      return NextResponse.json(
        { error: 'User not found. Please complete onboarding.', profileIncomplete: true },
        { status: 404 }
      )
    }

    const profile: UserProfile | null = user.profiles

    if (!profile || !profile.completed) {
      return NextResponse.json(
        { error: 'Please complete your freelancer profile before generating proposals.', profileIncomplete: true },
        { status: 400 }
      )
    }

    // Reset daily counter if new day
    const today = new Date().toISOString().split('T')[0]
    if (user.last_reset_date !== today) {
      await supabase
        .from('users')
        .update({ generations_today: 0, last_reset_date: today })
        .eq('clerk_id', userId)
      user.generations_today = 0
    }

    // Enforce 15-generation daily limit on Free plan
    if (user.plan !== 'pro' && user.generations_today >= 15) {
      return NextResponse.json(
        { error: 'Daily limit reached. Upgrade to Pro for unlimited generations.', upgradeRequired: true },
        { status: 403 }
      )
    }

    // Parse input
    const body = await req.json()
    const { jobTitle, jobDescription, jobBudget, platform, extraContext, model, budgetType } = body

    if (!jobDescription || jobDescription.trim().length < 50) {
      return NextResponse.json(
        { error: 'Job description is too short. Paste the full description for best results.' },
        { status: 400 }
      )
    }

    if (user.plan !== 'pro' && platform !== 'upwork' && platform !== 'general') {
      return NextResponse.json(
        { error: `Generating proposals for ${platform} is a Pro feature.`, upgradeRequired: true },
        { status: 403 }
      )
    }

    const systemPrompt = buildSystemPrompt(profile, platform)
    const userPrompt   = buildUserPrompt({ jobTitle, jobDescription, jobBudget, platform, extraContext, budgetType })

    let rawResult: string

    // Both plans use OpenAI — Pro gets gpt-4.1 (or free if requested), Free gets gpt-4o-mini
    const requestedModel = model === 'gpt-4.1' && user.plan === 'pro' ? PRO_MODEL : FREE_MODEL

    const response = await openai.chat.completions.create({
      model:           requestedModel,
      max_tokens:      2048,
      messages:        [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ],
      response_format: { type: 'json_object' },
    })
    rawResult = response.choices[0].message.content || ''

    // Parse JSON safely
    let parsed: {
      proposal:      string
      pricing:       Array<{ item: string; hours: number; rate: number; total: number; notes: string }>
      timeline:      Array<{ phase: string; duration: string; deliverables: string[] }>
      followup:      string
      humanise_tips: any[]
    }

    try {
      const cleaned = rawResult
        .replace(/^```json\s*/m, '')
        .replace(/^```\s*/m, '')
        .replace(/```\s*$/m, '')
        .trim()
      parsed = JSON.parse(cleaned)
    } catch {
      parsed = {
        proposal:      rawResult,
        pricing:       [],
        timeline:      [],
        followup:      '',
        humanise_tips: [],
      }
    }

    // Track usage (no hard limit)
    await supabase
      .from('users')
      .update({ generations_today: user.generations_today + 1 })
      .eq('clerk_id', userId)

    // Save to history
    const { data: saved } = await supabase
      .from('proposals')
      .insert({
        user_id:         user.id,
        job_title:       jobTitle || null,
        job_description: jobDescription,
        job_budget:      jobBudget || null,
        platform:        platform || 'general',
        extra_context:   extraContext || null,
        proposal_text:   parsed.proposal,
        pricing_table:   parsed.pricing,
        timeline:        parsed.timeline,
        followup_text:   parsed.followup,
        humanise_tips:   parsed.humanise_tips,
        model_used:      requestedModel,
        word_count:      parsed.proposal?.split(' ').length ?? 0,
      })
      .select('id')
      .single()

    const generationsLeft = user.plan === 'pro' ? null : Math.max(0, 15 - (user.generations_today + 1))

    return NextResponse.json({
      success:         true,
      proposalId:      saved?.id,
      output:          parsed,
      modelUsed:       requestedModel === PRO_MODEL ? 'GPT-4.1' : 'GPT-4o mini',
      generationsLeft,
    })

  } catch (error) {
    console.error('[/api/generate]', error)
    return NextResponse.json(
      { error: 'Generation failed. Please try again.' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { auth, currentUser } from '@clerk/nextjs/server'
import { createAdminClient } from '@/lib/supabase'

async function getOrCreateUser(supabase: any, clerkUserId: string) {
  let { data: user } = await supabase
    .from('users')
    .select('id, name, plan')
    .eq('clerk_id', clerkUserId)
    .single()

  if (!user) {
    try {
      const clerkUser = await currentUser()
      if (clerkUser) {
        const email = clerkUser.emailAddresses.find((e) => e.id === clerkUser.primaryEmailAddressId)?.emailAddress || clerkUser.emailAddresses[0]?.emailAddress
        const name = [clerkUser.firstName, clerkUser.lastName].filter(Boolean).join(' ') || null

        if (email) {
          const { data: newUser, error: insertError } = await supabase
            .from('users')
            .insert({ clerk_id: clerkUserId, email, name, updated_at: new Date().toISOString() })
            .select('id, name, plan')
            .single()

          if (!insertError && newUser) {
            user = newUser
          } else if (insertError) {
            console.error('Failed to create user in db:', insertError)
          }
        }
      }
    } catch (err) {
      console.error('Error fetching/creating user from Clerk:', err)
    }
  }

  return user
}

export async function GET() {
  const { userId } = await auth()
  if (!userId) return NextResponse.json({ error: 'Unauthorised' }, { status: 401 })

  const supabase = createAdminClient()

  const user = await getOrCreateUser(supabase, userId)
  if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 })

  const { data: profile } = await supabase
    .from('profiles')
    .select('*')
    .eq('user_id', user.id)
    .single()

  return NextResponse.json({ profile: profile ?? null, defaultName: user.name ?? null, plan: user.plan })
}

export async function POST(req: NextRequest) {
  const { userId } = await auth()
  if (!userId) return NextResponse.json({ error: 'Unauthorised' }, { status: 401 })

  const supabase = createAdminClient()

  const user = await getOrCreateUser(supabase, userId)
  if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 })

  const body = await req.json()

  const { data, error } = await supabase
    .from('profiles')
    .upsert(
      { ...body, user_id: user.id, updated_at: new Date().toISOString() },
      { onConflict: 'user_id' }
    )
    .select()
    .single()

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })

  return NextResponse.json({ profile: data })
}

'use client'

import Image from 'next/image'

import { useState, useCallback, useEffect } from 'react'
import { InputPanel, type InputFormData } from '@/components/dashboard/InputPanel'
import { OutputPanel } from '@/components/dashboard/OutputPanel'
import type { ProposalOutput } from '@/types/proposal'
import { ThemeToggle } from '@/components/shared/ThemeToggle'

export default function DashboardPage() {
  const [output, setOutput]               = useState<ProposalOutput | null>(null)
  const [modelUsed, setModelUsed]         = useState<string | null>(null)
  const [proposalId, setProposalId]       = useState<string | null>(null)
  const [isGenerating, setIsGenerating]   = useState(false)
  const [generationsLeft, setGenerationsLeft] = useState<number | null>(null)
  const [error, setError]                 = useState<string | null>(null)
  const [lastInput, setLastInput]         = useState<InputFormData | null>(null)
  const [initialInputValues, setInitialInputValues] = useState<Partial<InputFormData> | undefined>(undefined)
  const [inputKey, setInputKey]           = useState(0)

  // Plan & Model selector states
  const [plan, setPlan]                   = useState<'free' | 'pro'>('free')
  const [selectedModel, setSelectedModel] = useState<'gpt-4o-mini' | 'gpt-4.1'>('gpt-4o-mini')
  const [isModelDropdownOpen, setIsModelDropdownOpen] = useState(false)

  // Load plan and initial proposal if passed in URL query parameter
  useEffect(() => {
    // Fetch profile to get plan
    fetch('/api/profile')
      .then((r) => r.json())
      .then(({ plan: p }) => {
        if (p) {
          setPlan(p)
          if (p === 'pro') {
            setSelectedModel('gpt-4.1')
          }
        }
      })
      .catch(console.error)

    const params = new URLSearchParams(window.location.search)
    const proposalIdParam = params.get('proposal')
    if (proposalIdParam) {
      fetch(`/api/history?id=${proposalIdParam}`)
        .then((r) => r.json())
        .then(({ proposal }) => {
          if (proposal) {
            const loadedInput: InputFormData = {
              platform:       (proposal.platform || 'upwork') as any,
              jobTitle:       proposal.job_title || '',
              budgetType:     (proposal.job_budget?.toLowerCase().includes('hr') || proposal.job_budget?.toLowerCase().includes('hour')) ? 'hourly' : 'fixed',
              jobBudget:      proposal.job_budget || '',
              jobDescription: proposal.job_description || '',
              extraContext:   proposal.extra_context || '',
            }
            setInitialInputValues(loadedInput)
            setLastInput(loadedInput)

            // Set selected model state to match the loaded proposal
            if (proposal.model_used?.includes('gpt-4.1')) {
              setSelectedModel('gpt-4.1')
            } else {
              setSelectedModel('gpt-4o-mini')
            }

            setOutput({
              proposal:      proposal.proposal_text ?? '',
              pricing:       proposal.pricing_table ?? [],
              timeline:      proposal.timeline ?? [],
              followup:      proposal.followup_text ?? '',
              humanise_tips: proposal.humanise_tips ?? [],
            })
            const modelLabel = proposal.model_used?.includes('gpt-4.1')
              ? 'GPT-4.1 (Pro)'
              : proposal.model_used?.includes('gpt-4o-mini')
              ? 'GPT-4o mini'
              : proposal.model_used?.includes('gemini')
              ? 'Gemini Flash'
              : proposal.model_used || 'GPT-4o mini'
            setModelUsed(modelLabel)
            setProposalId(proposal.id)
          }
        })
        .catch(console.error)
    }
  }, [])

  const generate = useCallback(async (data: InputFormData) => {
    setIsGenerating(true)
    setError(null)
    setLastInput(data)

    try {
      const res = await fetch('/api/generate', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ ...data, model: selectedModel }),
      })

      const json = await res.json()

      if (!res.ok) {
        if (json.upgradeRequired) {
          setError('Daily limit reached. Upgrade to Pro for unlimited generations.')
        } else if (json.profileIncomplete) {
          window.location.href = '/dashboard/profile'
        } else {
          setError(json.error ?? 'Generation failed. Please try again.')
        }
        return
      }

      setOutput(json.output)
      setModelUsed(json.modelUsed)
      setProposalId(json.proposalId)
      if (json.generationsLeft !== null) {
        setGenerationsLeft(json.generationsLeft)
      }
    } catch {
      setError('Network error. Please check your connection and try again.')
    } finally {
      setIsGenerating(false)
    }
  }, [selectedModel])

  const regenerate = useCallback(() => {
    if (lastInput) generate(lastInput)
  }, [lastInput, generate])

  const handleNewBid = useCallback(() => {
    if (output) {
      const confirmClear = window.confirm('Are you sure you want to start a new bid? Your current generated proposal will be cleared.')
      if (!confirmClear) return
    }
    setOutput(null)
    setModelUsed(null)
    setProposalId(null)
    setError(null)
    setLastInput(null)
    setInitialInputValues(undefined)
    setInputKey((k) => k + 1)
  }, [output])

  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false)

  return (
    <div className="min-h-screen bg-[--color-bc-surface]">
      {/* Nav */}
      <header className="bg-[--color-bc-white] border-b border-[--color-bc-border] px-6 py-4 relative">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="sm:hidden p-1.5 text-[--color-bc-ink] hover:bg-[--color-bc-surface] rounded-lg cursor-pointer">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                {isMobileMenuOpen ? (
                  <><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></>
                ) : (
                  <><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></>
                )}
              </svg>
            </button>
            <a href="/" className="font-bold text-[--color-bc-blue] text-xl tracking-tight flex items-center gap-2">
              <Image src="/icon.svg" alt="BidCopy Logo" width={19} height={24} className="rounded-sm" />
              BidCopy
            </a>
          </div>
          <nav className="flex items-center gap-3 md:gap-6 text-sm">
            <div className="hidden sm:flex items-center gap-6">
              <a href="/dashboard/history" className="text-[--color-bc-muted] hover:text-[--color-bc-ink] transition-colors">History</a>
              <a href="/dashboard/profile" className="text-[--color-bc-muted] hover:text-[--color-bc-ink] transition-colors">Profile</a>
            </div>
            <ThemeToggle />
            <a href="/dashboard/upgrade" className="bg-[--color-bc-blue] text-white px-3 md:px-4 py-2 rounded-lg text-sm font-semibold hover:bg-[--color-bc-blue-dark] transition-colors whitespace-nowrap">
              Go Pro
            </a>
          </nav>
        </div>

        {isMobileMenuOpen && (
          <div className="sm:hidden absolute top-full left-0 right-0 bg-[--color-bc-white] border-b border-[--color-bc-border] p-4 flex flex-col gap-4 shadow-xl z-50">
            <a href="/dashboard/history" onClick={() => setIsMobileMenuOpen(false)} className="text-[--color-bc-ink] font-medium hover:text-[--color-bc-blue]">History</a>
            <a href="/dashboard/profile" onClick={() => setIsMobileMenuOpen(false)} className="text-[--color-bc-ink] font-medium hover:text-[--color-bc-blue]">Profile</a>
          </div>
        )}
      </header>

      {/* Error banner */}
      {error && (
        <div className="bg-red-50 dark:bg-red-950/20 border-b border-red-200 dark:border-red-900/30 px-6 py-3">
          <div className="max-w-7xl mx-auto flex items-center justify-between">
            <p className="text-sm text-red-700 dark:text-red-400">{error}</p>
            <div className="flex gap-3">
              {error.includes('Daily limit') && (
                <a href="/dashboard/upgrade" className="text-sm font-semibold text-red-700 dark:text-red-400 underline">Upgrade →</a>
              )}
              <button onClick={() => setError(null)} className="text-sm text-red-500 dark:text-red-400 hover:text-red-700 dark:hover:text-red-300">Dismiss</button>
            </div>
          </div>
        </div>
      )}

      {/* Main layout */}
      <main className="max-w-7xl mx-auto px-6 py-8">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold text-[--color-bc-ink]">Generate a bid</h1>
            <p className="text-[--color-bc-muted] text-sm mt-1">Paste a job description → get a complete bid package in 30 seconds.</p>
          </div>

          <div className="flex items-center gap-3 flex-shrink-0">
            <button
              onClick={handleNewBid}
              className="flex items-center gap-1.5 px-4 py-2 border border-[--color-bc-border] rounded-xl text-sm font-semibold text-[--color-bc-ink] bg-[--color-bc-white] hover:bg-[--color-bc-surface] shadow-sm transition-all cursor-pointer"
            >
              <span className="text-xs">+</span> New bid
            </button>

            {/* Model Selector Dropdown */}
            <div className="relative flex-shrink-0">
              <button
                onClick={() => setIsModelDropdownOpen(!isModelDropdownOpen)}
                className="flex items-center gap-2 px-4 py-2 bg-[--color-bc-white] border border-[--color-bc-border] rounded-xl text-sm font-semibold text-[--color-bc-ink] hover:bg-[--color-bc-surface] shadow-sm transition-all cursor-pointer"
              >
                <span>{selectedModel === 'gpt-4.1' ? 'GPT-4.1 (Pro)' : 'GPT-4o mini'}</span>
                <span className="text-gray-400 text-xs">▼</span>
              </button>

            {isModelDropdownOpen && (
              <>
                <div className="fixed inset-0 z-40" onClick={() => setIsModelDropdownOpen(false)} />
                <div className="absolute right-0 mt-2 w-72 bg-[--color-bc-white] border border-[--color-bc-border] rounded-2xl shadow-xl z-50 p-2 space-y-1">
                  
                  {/* GPT-4.1 Pro Option */}
                  <div
                    onClick={() => {
                      if (plan === 'pro') {
                        setSelectedModel('gpt-4.1')
                        setIsModelDropdownOpen(false)
                      }
                    }}
                    className={`flex items-center justify-between p-3 rounded-xl transition-all ${
                      plan === 'pro'
                        ? 'cursor-pointer hover:bg-[--color-bc-surface]'
                        : 'bg-[--color-bc-surface]/50'
                    }`}
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="font-semibold text-sm text-[--color-bc-ink] flex items-center gap-1.5">
                        GPT-4.1 (Pro)
                        {selectedModel === 'gpt-4.1' && (
                          <span className="text-xs text-[--color-bc-blue]">✓</span>
                        )}
                      </div>
                      <p className="text-[10px] text-[--color-bc-muted]">Our smartest model for complex challenges</p>
                    </div>
                    {plan !== 'pro' && (
                      <a
                        href="/dashboard/upgrade"
                        onClick={(e) => e.stopPropagation()}
                        className="bg-[--color-bc-blue] text-white px-2.5 py-1.5 rounded-lg text-[10px] font-semibold hover:bg-[--color-bc-blue-dark] transition-colors flex-shrink-0 ml-2"
                      >
                        Upgrade
                      </a>
                    )}
                  </div>

                  {/* Divider */}
                  <div className="h-px bg-[--color-bc-border] my-1" />

                  {/* GPT-4o Mini Option */}
                  <div
                    onClick={() => {
                      setSelectedModel('gpt-4o-mini')
                      setIsModelDropdownOpen(false)
                    }}
                    className="flex items-center justify-between p-3 rounded-xl cursor-pointer hover:bg-[--color-bc-surface] transition-all"
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="font-semibold text-sm text-[--color-bc-ink] flex items-center gap-1.5">
                        GPT-4o mini
                        {selectedModel === 'gpt-4o-mini' && (
                          <span className="text-xs text-[--color-bc-blue]">✓</span>
                        )}
                      </div>
                      <p className="text-[10px] text-[--color-bc-muted]">Fastest model for quick drafts</p>
                    </div>
                  </div>

                </div>
              </>
            )}
          </div>
        </div>
      </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Left: input */}
          <div className="bg-[--color-bc-white] border border-[--color-bc-border] rounded-xl p-6 flex flex-col min-h-[600px]">
            <InputPanel
              key={inputKey}
              onGenerate={generate}
              isGenerating={isGenerating}
              generationsLeft={generationsLeft}
              initialValues={initialInputValues}
            />
          </div>

          {/* Right: output */}
          <div className="bg-[--color-bc-white] border border-[--color-bc-border] rounded-xl p-6 flex flex-col min-h-[600px]">
            <OutputPanel
              output={output}
              modelUsed={modelUsed}
              proposalId={proposalId}
              onRegenerate={regenerate}
              isGenerating={isGenerating}
            />
          </div>
        </div>
      </main>
    </div>
  )
}

'use client'

import Image from 'next/image'

import { useState, useEffect } from 'react'
import { useForm, useFieldArray } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Button } from '@/components/ui/Button'
import { Input } from '@/components/ui/Input'
import { Textarea } from '@/components/ui/Textarea'
import type { UserProfile } from '@/types/profile'
import { ThemeToggle } from '@/components/shared/ThemeToggle'

// ── Zod schema ──────────────────────────────────────────────
const profileSchema = z.object({
  name:          z.string().min(2, 'Enter your name'),
  headline:      z.string().min(10, 'Enter a headline (e.g. Full-stack developer · 5 yrs)'),
  bio:           z.string().min(50, 'Bio should be at least 50 characters'),
  skills:        z.string().min(3, 'Add at least one skill'),
  hourly_rate:   z.string().min(1, 'Enter your hourly rate'),
  currency:      z.enum(['USD', 'EUR', 'GBP', 'INR', 'AUD', 'CAD']),
  portfolio_url: z.string().url('Enter a valid URL').or(z.literal('')),
  tone:          z.enum(['professional', 'friendly', 'technical', 'bold']),
  speciality:    z.string().min(2, 'Enter your main speciality'),
  projects: z.array(z.object({
    name:        z.string().min(1, 'Project name required'),
    description: z.string().min(10, 'Describe the project'),
    result:      z.string().min(5, 'What was the result?'),
    url:         z.string().optional(),
  })).min(1, 'Add at least one project'),
})

type ProfileForm = z.infer<typeof profileSchema>

// ── Step config ──────────────────────────────────────────────
const STEPS = [
  { title: 'About you',      description: 'Tell us who you are' },
  { title: 'Skills & rates', description: 'Your expertise and pricing' },
  { title: 'Your projects',  description: 'Add 1–3 past projects for context' },
  { title: 'Tone & style',   description: 'How should your proposals sound?' },
]

const TONES = [
  { id: 'professional', label: 'Professional', desc: 'Formal but warm. Measured confidence.' },
  { id: 'friendly',     label: 'Friendly',     desc: 'Conversational and approachable.' },
  { id: 'technical',    label: 'Technical',    desc: 'Precise, detail-oriented.' },
  { id: 'bold',         label: 'Bold',         desc: 'Direct and punchy. No hedging.' },
] as const

const CURRENCIES = ['USD', 'EUR', 'GBP', 'INR', 'AUD', 'CAD'] as const

export default function ProfilePage() {
  const [step, setStep]     = useState(0)
  const [saving, setSaving] = useState(false)
  const [saved, setSaved]   = useState(false)
  const [loading, setLoading] = useState(true)
  const [error, setError]   = useState<string | null>(null)

  const { register, handleSubmit, control, watch, setValue, trigger, formState: { errors } } = useForm<ProfileForm>({
    resolver:      zodResolver(profileSchema),
    defaultValues: {
      currency: 'USD',
      tone:     'professional',
      projects: [{ name: '', description: '', result: '', url: '' }],
    },
  })

  const { fields, append, remove } = useFieldArray({ control, name: 'projects' })
  const selectedTone = watch('tone')

  // Load existing profile & recover draft from localStorage
  useEffect(() => {
    fetch('/api/profile')
      .then((r) => r.json())
      .then(({ profile, defaultName }) => {
        const draft = localStorage.getItem('bidcopy_profile_draft')
        let draftData: any = null
        if (draft) {
          try {
            draftData = JSON.parse(draft)
          } catch (e) {}
        }

        if (profile) {
          setValue('name',          draftData?.name ?? profile.name ?? defaultName ?? '')
          setValue('headline',      draftData?.headline ?? profile.headline ?? '')
          setValue('bio',           draftData?.bio ?? profile.bio ?? '')
          setValue('skills',        draftData?.skills ?? (profile.skills ?? []).join(', '))
          setValue('hourly_rate',   draftData?.hourly_rate ?? String(profile.hourly_rate ?? 50))
          setValue('currency',      draftData?.currency ?? profile.currency ?? 'USD')
          setValue('portfolio_url', draftData?.portfolio_url ?? profile.portfolio_url ?? '')
          setValue('tone',          draftData?.tone ?? profile.tone ?? 'professional')
          setValue('speciality',    draftData?.speciality ?? profile.speciality ?? '')
          if (draftData?.projects) {
            setValue('projects', draftData.projects)
          } else if (profile.projects?.length) {
            setValue('projects', profile.projects)
          }
          if (draftData?.step !== undefined) {
            setStep(draftData.step)
          }
        } else {
          setValue('name',          draftData?.name ?? defaultName ?? '')
          setValue('headline',      draftData?.headline ?? '')
          setValue('bio',           draftData?.bio ?? '')
          setValue('skills',        draftData?.skills ?? '')
          setValue('hourly_rate',   draftData?.hourly_rate ?? '50')
          setValue('currency',      draftData?.currency ?? 'USD')
          setValue('portfolio_url', draftData?.portfolio_url ?? '')
          setValue('tone',          draftData?.tone ?? 'professional')
          setValue('speciality',    draftData?.speciality ?? '')
          if (draftData?.projects) setValue('projects', draftData.projects)
          if (draftData?.step !== undefined) setStep(draftData.step)
        }
      })
      .finally(() => setLoading(false))
  }, [setValue])

  const onSubmit = async (data: ProfileForm) => {
    setSaving(true)
    setError(null)
    try {
      const payload: Partial<UserProfile> = {
        ...data,
        hourly_rate: Number(data.hourly_rate),
        skills:    data.skills.split(',').map((s) => s.trim()).filter(Boolean),
        completed: true,
      }
      const res = await fetch('/api/profile', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(payload),
      })
      if (res.ok) {
        setSaved(true)
        localStorage.removeItem('bidcopy_profile_draft')
        setTimeout(() => (window.location.href = '/dashboard'), 1500)
      } else {
        const errData = await res.json().catch(() => ({}))
        setError(errData.error || 'Failed to save profile. Please check all fields or try again.')
      }
    } catch (e: any) {
      setError(e.message || 'An unexpected error occurred. Please try again.')
    } finally {
      setSaving(false)
    }
  }

  const bioVal = watch('bio') || ''
  const headlineVal = watch('headline') || ''

  const handleContinue = async () => {
    let fieldsToValidate: Array<keyof ProfileForm> = []
    if (step === 0) {
      fieldsToValidate = ['name', 'headline', 'bio', 'speciality']
    } else if (step === 1) {
      fieldsToValidate = ['skills', 'hourly_rate', 'currency', 'portfolio_url']
    } else if (step === 2) {
      fieldsToValidate = ['projects']
    }

    const isValid = await trigger(fieldsToValidate)
    if (isValid) {
      const nextStep = step + 1
      setStep(nextStep)
      localStorage.setItem('bidcopy_profile_draft', JSON.stringify({
        ...watch(),
        step: nextStep
      }))
    }
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[--color-bc-surface]">
        <div className="w-8 h-8 border-2 border-bc-blue border-t-transparent rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-[--color-bc-surface]">
      <header className="bg-[--color-bc-white] border-b border-[--color-bc-border] px-6 py-4">
        <div className="max-w-2xl mx-auto flex items-center justify-between">
          <a href="/" className="font-bold text-[--color-bc-blue] text-xl flex items-center gap-2"><Image src="/icon.svg" alt="BidCopy Logo" width={19} height={24} className="rounded-sm" />BidCopy</a>
          <div className="flex items-center gap-4">
            <ThemeToggle />
            <a href="/dashboard" className="text-sm text-[--color-bc-muted] hover:text-[--color-bc-ink]">← Back to dashboard</a>
          </div>
        </div>
      </header>

      <main className="max-w-2xl mx-auto px-6 py-12">
        {/* Progress */}
        <div className="flex gap-2 mb-10">
          {STEPS.map((s, i) => (
            <div key={i} className="flex-1">
              <div className={`h-1 rounded-full transition-all ${i <= step ? 'bg-[--color-bc-blue]' : 'bg-[--color-bc-border]'}`} />
              <p className={`text-xs mt-2 font-medium ${i === step ? 'text-[--color-bc-blue]' : 'text-[--color-bc-faint]'}`}>
                {s.title}
              </p>
            </div>
          ))}
        </div>

        <div className="mb-8">
          <h1 className="text-2xl font-bold text-[--color-bc-ink]">{STEPS[step].title}</h1>
          <p className="text-[--color-bc-muted] mt-1">{STEPS[step].description}</p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">

          {/* STEP 0 — About you */}
          {step === 0 && (
            <>
              <Input label="Your name" id="name" {...register('name')} error={errors.name?.message} placeholder="e.g. Rahul Sharma" />
              
              <div className="space-y-1">
                <Input label="Headline" id="headline" {...register('headline')} error={errors.headline?.message} placeholder="Full-stack developer · 5 years · React, Node.js" />
                <div className="flex justify-between items-center text-[10px] sm:text-xs">
                  <span className={errors.headline ? 'text-red-500 font-medium' : 'text-[--color-bc-muted]'}>
                    Min 10 characters required
                  </span>
                  <span className={`font-semibold ${headlineVal.length >= 10 ? 'text-green-600' : 'text-amber-600'}`}>
                    {headlineVal.length} characters {headlineVal.length >= 10 ? '✓' : ''}
                  </span>
                </div>
              </div>

              <div className="space-y-1">
                <Textarea label="Bio" id="bio" {...register('bio')} error={errors.bio?.message} rows={4}
                  placeholder="Write a short bio that captures your expertise. This goes directly into the AI prompt." />
                <div className="flex justify-between items-center text-[10px] sm:text-xs">
                  <span className={errors.bio ? 'text-red-500 font-medium' : 'text-[--color-bc-muted]'}>
                    Min 50 characters required for personalized proposals
                  </span>
                  <span className={`font-semibold ${bioVal.length >= 50 ? 'text-green-600' : 'text-amber-600'}`}>
                    {bioVal.length} / 50 characters {bioVal.length >= 50 ? '✓' : ''}
                  </span>
                </div>
              </div>

              <Input label="Speciality" id="speciality" {...register('speciality')} error={errors.speciality?.message} placeholder="e.g. SaaS products, e-commerce, mobile apps" />
            </>
          )}

          {/* STEP 1 — Skills & rates */}
          {step === 1 && (
            <>
              <Textarea label="Skills (comma-separated)" id="skills" {...register('skills')} error={errors.skills?.message} rows={3}
                placeholder="React, Next.js, TypeScript, Node.js, PostgreSQL, Tailwind CSS" />
              <div className="grid grid-cols-2 gap-4">
                <Input label="Hourly rate" id="hourly_rate" type="number" {...register('hourly_rate')} error={errors.hourly_rate?.message} placeholder="50" min="1" />
                <div className="flex flex-col gap-1.5">
                  <label className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide">Currency</label>
                  <select {...register('currency')} className="border border-[--color-bc-border] rounded-lg px-3 py-2.5 text-sm text-[--color-bc-ink] bg-[--color-bc-white] focus:outline-none focus:ring-2 focus:ring-[--color-bc-blue]/20 focus:border-[--color-bc-blue] transition-all">
                    {CURRENCIES.map((c) => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <Input label="Portfolio URL" id="portfolio_url" {...register('portfolio_url')} error={errors.portfolio_url?.message} placeholder="https://yourportfolio.com" />
            </>
          )}

          {/* STEP 2 — Projects */}
          {step === 2 && (
            <div className="space-y-6">
              {fields.map((field, i) => (
                <div key={field.id} className="border border-[--color-bc-border] rounded-xl p-5 space-y-4">
                  <div className="flex items-center justify-between">
                    <h3 className="font-semibold text-sm text-[--color-bc-ink]">Project {i + 1}</h3>
                    {fields.length > 1 && (
                      <button type="button" onClick={() => remove(i)} className="text-xs text-red-500 hover:text-red-700">Remove</button>
                    )}
                  </div>
                  <Input label="Project name" {...register(`projects.${i}.name`)} error={errors.projects?.[i]?.name?.message} placeholder="e.g. Medica Health Dashboard" />
                  <Textarea label="What you built" rows={2} {...register(`projects.${i}.description`)} error={errors.projects?.[i]?.description?.message}
                    placeholder="e.g. Built a React + Node.js dashboard for a healthcare startup tracking 10k patients" />
                  <Input label="Result / outcome" {...register(`projects.${i}.result`)} error={errors.projects?.[i]?.result?.message}
                    placeholder="e.g. Reduced reporting time by 40%, client raised Series A" />
                  <Input label="URL (optional)" {...register(`projects.${i}.url`)} placeholder="https://example.com" />
                </div>
              ))}
              {fields.length < 3 && (
                <button type="button" onClick={() => append({ name: '', description: '', result: '', url: '' })}
                  className="w-full border-2 border-dashed border-[--color-bc-border] rounded-xl py-3 text-sm text-[--color-bc-muted] hover:border-[--color-bc-blue] hover:text-[--color-bc-blue] transition-colors">
                  + Add another project
                </button>
              )}
            </div>
          )}

          {/* STEP 3 — Tone */}
          {step === 3 && (
            <div className="grid grid-cols-2 gap-3">
              {TONES.map((t) => (
                <button key={t.id} type="button" onClick={() => setValue('tone', t.id)}
                  className={`p-4 rounded-xl border-2 text-left transition-all ${
                    selectedTone === t.id
                      ? 'border-[--color-bc-blue] bg-[--color-bc-blue-light]'
                      : 'border-[--color-bc-border] hover:border-[--color-bc-blue]/40'
                  }`}>
                  <div className="font-semibold text-sm text-[--color-bc-ink] mb-1">{t.label}</div>
                  <div className="text-xs text-[--color-bc-muted]">{t.desc}</div>
                </button>
              ))}
            </div>
          )}

          {/* Submission / validation errors */}
          {error && (
            <div className="p-4 rounded-xl border border-red-200 bg-red-50 text-sm text-red-600 font-medium">
              {error}
            </div>
          )}

          {/* Navigation */}
          <div className="flex gap-3 pt-2">
            {step > 0 && (
              <Button type="button" variant="secondary" onClick={() => {
                const prevStep = step - 1
                setStep(prevStep)
                localStorage.setItem('bidcopy_profile_draft', JSON.stringify({
                  ...watch(),
                  step: prevStep
                }))
              }} className="flex-1">
                ← Back
              </Button>
            )}
            {step < STEPS.length - 1 ? (
              <Button type="button" onClick={handleContinue} className="flex-1">
                Continue →
              </Button>
            ) : (
              <Button type="submit" loading={saving} className="flex-1">
                {saved ? '✓ Saved! Redirecting…' : 'Save profile & start generating'}
              </Button>
            )}
          </div>

        </form>
      </main>
    </div>
  )
}

'use client'

import Image from 'next/image'

import { useState } from 'react'
import { Check } from 'lucide-react'
import { Button } from '@/components/ui/Button'

const PRO_FEATURES = [
  'Unlimited bid generations',
  'GPT-4.1 AI — best quality',
  'Full proposal history',
  'Priority generation speed',
  'All 4 platforms supported',
  'Humanise Checklist on every bid',
  'Pricing breakdown + timeline + follow-up',
]

declare global {
  interface Window {
    Razorpay: new (options: Record<string, unknown>) => { open: () => void }
  }
}

export default function UpgradePage() {
  const [loading, setLoading] = useState(false)
  const [success, setSuccess] = useState(false)

  const handleUpgrade = async () => {
    setLoading(true)
    try {
      // Load Razorpay script
      if (!window.Razorpay) {
        await new Promise<void>((resolve, reject) => {
          const script = document.createElement('script')
          script.src = 'https://checkout.razorpay.com/v1/checkout.js'
          script.onload = () => resolve()
          script.onerror = () => reject(new Error('Failed to load Razorpay'))
          document.body.appendChild(script)
        })
      }

      const res = await fetch('/api/create-order', { method: 'POST' })
      const { orderId, amount, currency, keyId } = await res.json()

      const rzp = new window.Razorpay({
        key:         keyId,
        amount,
        currency,
        name:        'BidCopy',
        description: 'Pro Plan — Unlimited bid generations',
        order_id:    orderId,
        handler: async (response: { razorpay_order_id: string; razorpay_payment_id: string; razorpay_signature: string }) => {
          const verify = await fetch('/api/verify-payment', {
            method:  'POST',
            headers: { 'Content-Type': 'application/json' },
            body:    JSON.stringify(response),
          })
          if (verify.ok) {
            setSuccess(true)
            setTimeout(() => (window.location.href = '/dashboard'), 2000)
          }
        },
        theme: { color: '#2563eb' },
      })

      rzp.open()
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-[--color-bc-surface] flex items-center justify-center px-6 py-20">
      <div className="max-w-md w-full">
        <div className="text-center mb-10">
          <a href="/" className="font-bold text-[--color-bc-blue] text-xl flex items-center gap-2"><Image src="/icon.svg" alt="BidCopy Logo" width={19} height={24} className="rounded-sm" />BidCopy</a>
          <h1 className="text-3xl font-bold text-[--color-bc-ink] mt-6 mb-2">Upgrade to Pro</h1>
          <p className="text-[--color-bc-muted]">Unlimited generations. Better AI. Full history.</p>
        </div>

        <div className="bg-[--color-bc-dark-card] text-white rounded-2xl p-8">
          <div className="flex items-baseline gap-1 mb-2">
            <span className="text-5xl font-bold">₹499</span>
            <span className="text-white/60">/month</span>
          </div>
          <p className="text-white/60 text-sm mb-8">Cancel anytime. Billed monthly.</p>

          <ul className="space-y-3 mb-10">
            {PRO_FEATURES.map((f) => (
              <li key={f} className="flex items-center gap-3 text-sm">
                <Check size={16} className="text-[--color-bc-blue-mid] flex-shrink-0" />
                <span className="text-white/90">{f}</span>
              </li>
            ))}
          </ul>

          {success ? (
            <div className="text-center text-green-400 font-semibold">
              ✓ You&apos;re now Pro! Redirecting…
            </div>
          ) : (
            <Button onClick={handleUpgrade} loading={loading} className="w-full" size="lg">
              Upgrade now →
            </Button>
          )}
        </div>

        <p className="text-center text-xs text-[--color-bc-muted] mt-6">
          Secure payment via Razorpay. Cancel anytime from your profile.
        </p>
      </div>
    </div>
  )
}

'use client'

import { useEffect } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Button } from '@/components/ui/Button'

const schema = z.object({
  platform:       z.enum(['upwork', 'freelancer', 'contra', 'general']),
  jobTitle:       z.string().optional(),
  budgetType:     z.enum(['fixed', 'hourly']),
  jobBudget:      z.string().optional(),
  jobDescription: z.string().min(50, 'Paste the full job description (min 50 chars)'),
  extraContext:   z.string().optional(),
})

export type InputFormData = z.infer<typeof schema>

interface InputPanelProps {
  onGenerate:      (data: InputFormData) => void
  isGenerating:    boolean
  generationsLeft: number | null
  initialValues?:  Partial<InputFormData>
  plan?:           'free' | 'pro'
}

const PLATFORMS = [
  { id: 'upwork',     label: 'Upwork',     dotColor: 'bg-emerald-500' },
  { id: 'freelancer', label: 'Freelancer', dotColor: 'bg-blue-500' },
  { id: 'contra',     label: 'Contra',     dotColor: 'bg-teal-400' },
  { id: 'general',    label: 'General',    dotColor: 'bg-slate-400 dark:bg-slate-500' },
] as const

const PLATFORM_STYLES: Record<string, { selected: string; unselected: string }> = {
  upwork: {
    selected: 'border-emerald-500/80 bg-emerald-50/50 dark:bg-emerald-950/20 text-emerald-750 dark:text-emerald-400 ring-2 ring-emerald-500/10',
    unselected: 'border-[--color-bc-border] text-[--color-bc-muted] hover:border-emerald-500/40 hover:text-emerald-700 dark:hover:text-emerald-400',
  },
  freelancer: {
    selected: 'border-blue-500/80 bg-blue-50/50 dark:bg-blue-950/20 text-blue-750 dark:text-blue-400 ring-2 ring-blue-500/10',
    unselected: 'border-[--color-bc-border] text-[--color-bc-muted] hover:border-blue-500/40 hover:text-blue-700 dark:hover:text-blue-400',
  },
  contra: {
    selected: 'border-teal-500/80 bg-teal-50/50 dark:bg-teal-950/20 text-teal-750 dark:text-teal-400 ring-2 ring-teal-500/10',
    unselected: 'border-[--color-bc-border] text-[--color-bc-muted] hover:border-teal-500/40 hover:text-teal-700 dark:hover:text-teal-400',
  },
  general: {
    selected: 'border-slate-500/80 bg-slate-50/50 dark:bg-slate-800/40 text-slate-750 dark:text-slate-300 ring-2 ring-slate-500/10',
    unselected: 'border-[--color-bc-border] text-[--color-bc-muted] hover:border-slate-500/40 hover:text-slate-700 dark:hover:text-slate-300',
  },
}

export function InputPanel({ onGenerate, isGenerating, generationsLeft, initialValues, plan = 'free' }: InputPanelProps) {
  const {
    register,
    handleSubmit,
    watch,
    setValue,
    reset,
    formState: { errors },
  } = useForm<InputFormData>({
    resolver:      zodResolver(schema),
    defaultValues: { platform: 'upwork', budgetType: 'fixed' },
  })

  useEffect(() => {
    if (initialValues) {
      reset({ budgetType: 'fixed', ...initialValues })
    }
  }, [initialValues, reset])

  const loadSampleData = () => {
    reset({
      platform: 'upwork',
      jobTitle: 'Senior React Developer for Healthcare Dashboard',
      budgetType: 'fixed',
      jobBudget: '$2,500',
      jobDescription: 'We are seeking an experienced React developer to help us polish and build out our new patient analytics dashboard. The design is mostly done in Figma, but we need someone to build the frontend, hook up the charting library (Recharts), and implement smooth, premium transitions. Must have 3+ years experience with Next.js, TypeScript, and Tailwind CSS. Responsive design and WCAG AA accessibility compliance are highly important. The project needs to be delivered in 2 weeks.',
      extraContext: 'Focus on my extensive experience with Recharts and pixel-perfect UI execution.',
    })
  }

  const selectedPlatform = watch('platform')
  const budgetType = watch('budgetType') || 'fixed'

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      e.preventDefault()
      handleSubmit(onGenerate)()
    }
  }

  return (
    <form onSubmit={handleSubmit(onGenerate)} onKeyDown={handleKeyDown} className="flex flex-col gap-5 h-full">
      <input type="hidden" {...register('budgetType')} />

      {/* Platform */}
      <div>
        <p className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide mb-2">
          Platform
        </p>
        <div role="radiogroup" aria-label="Platform selection" className="grid grid-cols-2 md:grid-cols-4 gap-2">
          {PLATFORMS.map((p) => {
            const isLocked = plan !== 'pro' && p.id !== 'upwork' && p.id !== 'general'
            return (
              <button
                key={p.id}
                type="button"
                role="radio"
                aria-checked={selectedPlatform === p.id}
                onClick={() => {
                  if (isLocked) {
                    window.location.href = '/dashboard/upgrade'
                    return
                  }
                  setValue('platform', p.id)
                }}
                className={`relative py-3 sm:py-2.5 px-1 rounded-lg text-[11px] sm:text-xs font-semibold border transition-all flex items-center justify-center gap-1.5 cursor-pointer ${
                  selectedPlatform === p.id
                    ? PLATFORM_STYLES[p.id].selected
                    : PLATFORM_STYLES[p.id].unselected
                } ${isLocked ? 'opacity-50 cursor-not-allowed hover:border-[--color-bc-border] hover:text-[--color-bc-muted]' : ''}`}
              >
                {isLocked && <span className="absolute -top-1.5 -right-1.5 bg-[--color-bc-surface] border border-[--color-bc-border] text-[8px] rounded px-1 text-[--color-bc-ink-2]">PRO</span>}
                <span className={`w-1.5 h-1.5 rounded-full shrink-0 transition-all ${p.dotColor} ${
                  selectedPlatform === p.id ? 'scale-110 opacity-100' : 'opacity-60'
                }`} />
                {p.label}
              </button>
            )
          })}
        </div>
      </div>

      {/* Title + Budget */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        <div className="flex flex-col gap-1.5">
          <label htmlFor="jobTitle" className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide">
            Job title <span className="text-[--color-bc-faint] normal-case font-normal">(optional)</span>
          </label>
          <input
            {...register('jobTitle')}
            id="jobTitle"
            placeholder="e.g. Next.js developer needed"
            className="border border-[--color-bc-border] rounded-lg px-3 py-2.5 text-sm text-[--color-bc-ink] placeholder-bc-faint bg-[--color-bc-white] focus:outline-none focus:ring-2 focus:ring-bc-blue/20 focus:border-bc-blue transition-all"
          />
        </div>
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center justify-between">
            <label htmlFor="jobBudget" className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide">
              Budget <span className="text-[--color-bc-faint] normal-case font-normal">(optional)</span>
            </label>
            <div role="radiogroup" aria-label="Budget type" className="flex bg-[--color-bc-surface] p-0.5 rounded-md text-[10px] font-bold">
              <button
                type="button"
                role="radio"
                aria-checked={budgetType === 'fixed'}
                onClick={() => setValue('budgetType', 'fixed')}
                className={`px-2 py-0.5 rounded transition-all cursor-pointer ${
                  budgetType === 'fixed'
                    ? 'bg-[--color-bc-white] text-[--color-bc-ink] shadow-sm'
                    : 'text-[--color-bc-muted] hover:text-[--color-bc-ink]'
                }`}
              >
                Fixed
              </button>
              <button
                type="button"
                role="radio"
                aria-checked={budgetType === 'hourly'}
                onClick={() => setValue('budgetType', 'hourly')}
                className={`px-2 py-0.5 rounded transition-all cursor-pointer ${
                  budgetType === 'hourly'
                    ? 'bg-[--color-bc-white] text-[--color-bc-ink] shadow-sm'
                    : 'text-[--color-bc-muted] hover:text-[--color-bc-ink]'
                }`}
              >
                Hourly
              </button>
            </div>
          </div>
          <input
            {...register('jobBudget')}
            id="jobBudget"
            placeholder={budgetType === 'hourly' ? "e.g. $15 - $25 / hr" : "e.g. $500 or $1000 - $3000"}
            className="border border-[--color-bc-border] rounded-lg px-3 py-2.5 text-sm text-[--color-bc-ink] placeholder-bc-faint bg-[--color-bc-white] focus:outline-none focus:ring-2 focus:ring-bc-blue/20 focus:border-bc-blue transition-all"
          />
        </div>
      </div>

      {/* Job description */}
      <div className="flex-1 flex flex-col gap-1.5">
        <div className="flex justify-between items-center">
          <label htmlFor="jobDescription" className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide">
            Job description <span className="text-red-500">*</span>
          </label>
          <button
            type="button"
            onClick={loadSampleData}
            className="text-[10px] font-bold text-[--color-bc-blue] hover:underline uppercase tracking-wider transition-colors cursor-pointer"
          >
            💡 Load Sample Job
          </button>
        </div>
        <textarea
          {...register('jobDescription')}
          id="jobDescription"
          placeholder="Paste the full job description here. The more detail, the better the proposal."
          className={`flex-1 min-h-[200px] border rounded-lg px-3 py-2.5 text-sm text-[--color-bc-ink] placeholder-bc-faint bg-[--color-bc-white] resize-none focus:outline-none focus:ring-2 focus:ring-bc-blue/20 focus:border-bc-blue transition-all ${
            errors.jobDescription ? 'border-red-400' : 'border-[--color-bc-border]'
          }`}
        />
        {errors.jobDescription && (
          <p className="text-xs text-red-500">{errors.jobDescription.message}</p>
        )}
      </div>

      {/* Extra context */}
      <div className="flex flex-col gap-1.5">
        <label htmlFor="extraContext" className="text-xs font-semibold text-[--color-bc-ink-2] uppercase tracking-wide">
          Any extra context? <span className="text-[--color-bc-faint] normal-case font-normal">(optional)</span>
        </label>
        <textarea
          {...register('extraContext')}
          id="extraContext"
          rows={2}
          placeholder="e.g. 'Stress my Shopify experience' or 'Keep it under 300 words'"
          className="border border-[--color-bc-border] rounded-lg px-3 py-2.5 text-sm text-[--color-bc-ink] placeholder-bc-faint bg-[--color-bc-white] resize-none focus:outline-none focus:ring-2 focus:ring-bc-blue/20 focus:border-bc-blue transition-all"
        />
      </div>

      {/* Submit */}
      <div>
        <Button
          type="submit"
          loading={isGenerating}
          size="lg"
          className="w-full"
        >
          {isGenerating ? 'Generating your bid…' : 'Generate bid package →'}
        </Button>

        <div className="mt-2 text-[10px] text-[--color-bc-faint] text-center flex items-center justify-center gap-1">
          <span>Press</span>
          <kbd className="font-mono text-[9px] bg-[--color-bc-surface] border border-[--color-bc-border] px-1 py-0.5 rounded text-[--color-bc-ink-2]">Ctrl</kbd>
          <span>/</span>
          <kbd className="font-mono text-[9px] bg-[--color-bc-surface] border border-[--color-bc-border] px-1 py-0.5 rounded text-[--color-bc-ink-2]">⌘</kbd>
          <span>+</span>
          <kbd className="font-mono text-[9px] bg-[--color-bc-surface] border border-[--color-bc-border] px-1 py-0.5 rounded text-[--color-bc-ink-2]">Enter</kbd>
          <span>to generate</span>
        </div>

        {generationsLeft !== null && (
          <div className="mt-3 flex items-center justify-between text-xs text-[--color-bc-muted]">
            <span>
              <span className={`font-semibold ${generationsLeft <= 1 ? 'text-amber-600' : 'text-[--color-bc-ink]'}`}>
                {generationsLeft}
              </span>{' '}
              of 15 free generations remaining today
            </span>
            <a href="/dashboard/upgrade" className="text-[--color-bc-blue] hover:underline font-semibold">
              Go Pro →
            </a>
          </div>
        )}
      </div>

    </form>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { Copy, Check, RefreshCw, Star, Edit3, Eye, Clipboard, FileText, Lightbulb, Target, Sparkles } from 'lucide-react'
import { Badge } from '@/components/ui/Badge'
import { buildChecklist, countChecked, type HumaniseTip } from '@/lib/humanise'
import type { ProposalOutput } from '@/types/proposal'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'

interface OutputPanelProps {
  output:      ProposalOutput | null
  modelUsed:   string | null
  proposalId:  string | null
  onRegenerate: () => void
  isGenerating: boolean
}

type TabId = 'proposal' | 'pricing' | 'timeline' | 'followup'

const TABS: { id: TabId; label: string }[] = [
  { id: 'proposal', label: 'Proposal' },
  { id: 'pricing',  label: 'Pricing' },
  { id: 'timeline', label: 'Timeline' },
  { id: 'followup', label: 'Follow-up' },
]

export function OutputPanel({ output, modelUsed, onRegenerate, isGenerating }: OutputPanelProps) {
  const [activeTab, setActiveTab]   = useState<TabId>('proposal')
  const [copied, setCopied]         = useState<string | null>(null)
  const [rating, setRating]         = useState(0)
  const [checklist, setChecklist]   = useState<HumaniseTip[]>([])
  const [loadingStep, setLoadingStep] = useState(0)

  // Local proposal states to allow direct inline editing
  const [editedProposal, setEditedProposal] = useState<string>('')
  const [isEditingProposal, setIsEditingProposal] = useState(false)

  const totalPrice = output?.pricing.reduce((s, r) => s + r.total, 0) ?? 0

  useEffect(() => {
    if (isGenerating) {
      setLoadingStep(0)
      const interval = setInterval(() => {
        setLoadingStep((s) => (s < 3 ? s + 1 : s))
      }, 4000)
      return () => clearInterval(interval)
    }
  }, [isGenerating])

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      const isCopyShortcut = (e.altKey && e.key?.toLowerCase() === 'c') ||
                             ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key?.toLowerCase() === 'c')

      if (isCopyShortcut) {
        if (!output || isGenerating) return
        e.preventDefault()
        if (activeTab === 'proposal') {
          copy(editedProposal, 'proposal')
        } else if (activeTab === 'pricing') {
          copy(
            output.pricing.map((r) => `${r.item}\t${r.hours}h\t$${r.rate}/hr\t$${r.total}`).join('\n') + `\n\nTotal: $${totalPrice}`,
            'pricing'
          )
        } else if (activeTab === 'followup') {
          copy(output.followup, 'followup')
        }
      }
    }

    window.addEventListener('keydown', handleGlobalKeyDown)
    return () => {
      window.removeEventListener('keydown', handleGlobalKeyDown)
    }
  }, [activeTab, output, editedProposal, totalPrice, isGenerating])

  // Rebuild checklist & local proposal when output changes
  const [lastOutputKey, setLastOutputKey] = useState<string | null>(null)
  const outputKey = output?.proposal?.slice(0, 20) ?? null
  if (outputKey !== lastOutputKey) {
    setLastOutputKey(outputKey)
    setChecklist(output ? buildChecklist(output.humanise_tips) : [])
    setEditedProposal(output ? output.proposal : '')
    setIsEditingProposal(false)
    setActiveTab('proposal')
  }

  const copy = async (text: string, key: string) => {
    await navigator.clipboard.writeText(text)
    setCopied(key)
    setTimeout(() => setCopied(null), 2000)
  }

  const handleApplyTip = (tip: HumaniseTip) => {
    if (!tip.original || !tip.replacement) return
    if (editedProposal.includes(tip.original)) {
      setEditedProposal((prev) => prev.replace(tip.original, tip.replacement))
      setChecklist((prev) =>
        prev.map((t) => (t.id === tip.id ? { ...t, checked: true } : t))
      )
    }
  }

  const handleRevertTip = (tip: HumaniseTip) => {
    if (!tip.original || !tip.replacement) return
    if (editedProposal.includes(tip.replacement)) {
      setEditedProposal((prev) => prev.replace(tip.replacement, tip.original))
      setChecklist((prev) =>
        prev.map((t) => (t.id === tip.id ? { ...t, checked: false } : t))
      )
    }
  }

  const [copiedTipId, setCopiedTipId] = useState<string | null>(null)

  const handleCopyTipText = async (tipId: string, text: string) => {
    await navigator.clipboard.writeText(text)
    setCopiedTipId(tipId)
    setTimeout(() => setCopiedTipId(null), 2000)
  }

  if (isGenerating) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-center p-12">
        <div className="relative w-16 h-16 mb-6">
          <div className="absolute inset-0 border-4 border-bc-blue/20 rounded-full" />
          <div className="absolute inset-0 border-4 border-t-bc-blue rounded-full animate-spin" />
        </div>
        <h3 className="font-semibold text-[--color-bc-ink] text-lg mb-2">Generating your bid package</h3>
        <p className="text-sm text-[--color-bc-muted] max-w-xs leading-relaxed mb-8">
          Our AI is writing your proposal, calculating project milestones, and tailoring the pricing.
        </p>
        <div className="w-full max-w-xs bg-[--color-bc-surface] border border-[--color-bc-border] rounded-xl p-5 space-y-4">
          <LoadingStep step={0} currentStep={loadingStep} label="Analyzing job details..." />
          <LoadingStep step={1} currentStep={loadingStep} label="Selecting relevant projects..." />
          <LoadingStep step={2} currentStep={loadingStep} label="Polishing tone & style..." />
          <LoadingStep step={3} currentStep={loadingStep} label="Drafting proposal & pricing..." />
        </div>
      </div>
    )
  }

  if (!output) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-center border-2 border-dashed border-[--color-bc-border] rounded-xl p-12">
        <div className="w-16 h-16 rounded-2xl bg-[--color-bc-surface] border border-[--color-bc-border] flex items-center justify-center mb-5 text-[--color-bc-muted] shadow-sm">
          <FileText className="w-8 h-8 text-[--color-bc-blue]" />
        </div>
        <h3 className="font-semibold text-[--color-bc-ink] text-lg mb-2">Your bid package will appear here</h3>
        <p className="text-sm text-[--color-bc-muted] max-w-xs leading-relaxed">
          Paste a job description on the left and click generate. You&apos;ll get a complete proposal, pricing breakdown, timeline, and follow-up message.
        </p>
      </div>
    )
  }

  return (
    <div className="flex flex-col h-full min-h-0">

      {/* Header */}
      <div className="flex items-center justify-between mb-4 flex-shrink-0">
        <div className="flex items-center gap-2">
          <Badge variant="blue">{modelUsed}</Badge>
          <span className="text-xs text-[--color-bc-faint]">
            {editedProposal.split(/\s+/).filter(Boolean).length} words
          </span>
        </div>
        <button
          onClick={onRegenerate}
          disabled={isGenerating}
          className="flex items-center gap-1.5 text-xs text-[--color-bc-muted] hover:text-[--color-bc-ink] transition-colors disabled:opacity-40"
        >
          <RefreshCw size={12} className={isGenerating ? 'animate-spin' : ''} />
          Regenerate
        </button>
      </div>

      {/* Tabs */}
      <div role="tablist" aria-label="Bid package sections" className="flex overflow-x-auto whitespace-nowrap border-b border-[--color-bc-border] mb-4 flex-shrink-0 hide-scrollbar">
        {TABS.map((tab) => (
          <button
            key={tab.id}
            id={`tab-${tab.id}`}
            role="tab"
            aria-selected={activeTab === tab.id}
            aria-controls={`tabpanel-${tab.id}`}
            onClick={() => setActiveTab(tab.id)}
            className={`px-4 py-2.5 text-sm font-medium border-b-2 transition-colors -mb-px ${
              activeTab === tab.id
                ? 'border-[--color-bc-blue] text-[--color-bc-blue]'
                : 'border-transparent text-[--color-bc-muted] hover:text-[--color-bc-ink]'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab content */}
      <div className="flex-1 overflow-y-auto min-h-0 pr-1">

        {/* PROPOSAL */}
        {activeTab === 'proposal' && (
          <div id="tabpanel-proposal" role="tabpanel" aria-labelledby="tab-proposal" className="space-y-4">
            {/* Read / Edit Toggle Header */}
            <div className="flex items-center justify-between border-b border-[--color-bc-border] pb-2 flex-shrink-0">
              <span className="text-xs text-[--color-bc-muted] font-medium">Refine your proposal below</span>
              <div className="flex bg-[--color-bc-surface] p-0.5 rounded-lg text-xs">
                <button
                  onClick={() => setIsEditingProposal(false)}
                  className={`flex items-center gap-1 px-3 py-1 rounded-md transition-all cursor-pointer ${
                    !isEditingProposal
                      ? 'bg-[--color-bc-white] text-[--color-bc-ink] font-semibold shadow-sm'
                      : 'text-[--color-bc-muted] hover:text-[--color-bc-ink]'
                  }`}
                >
                  <Eye size={12} />
                  Preview
                </button>
                <button
                  onClick={() => setIsEditingProposal(true)}
                  className={`flex items-center gap-1 px-3 py-1 rounded-md transition-all cursor-pointer ${
                    isEditingProposal
                      ? 'bg-[--color-bc-white] text-[--color-bc-ink] font-semibold shadow-sm'
                      : 'text-[--color-bc-muted] hover:text-[--color-bc-ink]'
                  }`}
                >
                  <Edit3 size={12} />
                  Edit
                </button>
              </div>
            </div>

            {/* Proposal Content Area */}
            {isEditingProposal ? (
              <ProposalEditor
                value={editedProposal}
                onChange={setEditedProposal}
              />
            ) : (
              <div className="text-sm text-[--color-bc-ink] leading-relaxed border border-transparent px-1 min-h-[400px]">
                <ReactMarkdown
                  remarkPlugins={[remarkGfm]}
                  components={{
                    h1: ({node, ...props}) => <h1 className="text-lg font-bold text-[--color-bc-ink] mt-4 mb-2 first:mt-0" {...props} />,
                    h2: ({node, ...props}) => <h2 className="text-base font-bold text-[--color-bc-ink] mt-4 mb-2 first:mt-0" {...props} />,
                    h3: ({node, ...props}) => <h3 className="text-sm font-bold text-[--color-bc-ink] mt-3 mb-1 first:mt-0" {...props} />,
                    p: ({node, ...props}) => <p className="mb-3 last:mb-0 leading-relaxed text-[--color-bc-ink-2]" {...props} />,
                    ul: ({node, ...props}) => <ul className="list-disc pl-5 mb-3 space-y-1.5" {...props} />,
                    ol: ({node, ...props}) => <ol className="list-decimal pl-5 mb-3 space-y-1.5" {...props} />,
                    li: ({node, ...props}) => <li className="text-sm text-[--color-bc-ink-2]" {...props} />,
                    strong: ({node, ...props}) => <strong className="font-semibold text-[--color-bc-ink]" {...props} />,
                  }}
                >
                  {editedProposal}
                </ReactMarkdown>
              </div>
            )}

            <button
              onClick={() => copy(editedProposal, 'proposal')}
              className="flex items-center gap-2 text-xs bg-[--color-bc-blue] text-white px-4 py-2 rounded-lg hover:bg-[--color-bc-blue-dark] transition-colors font-semibold"
            >
              {copied === 'proposal' ? (
                <>
                  <Check size={12} /> Copied!
                </>
              ) : (
                <>
                  <Copy size={12} />
                  <span>Copy proposal</span>
                  <span className="flex items-center gap-1 ml-1.5 opacity-80 select-none">
                    <span>(</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">Alt</kbd>
                    <span>+</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">C</kbd>
                    <span>)</span>
                  </span>
                </>
              )}
            </button>
          </div>
        )}

        {/* PRICING */}
        {activeTab === 'pricing' && (
          <div id="tabpanel-pricing" role="tabpanel" aria-labelledby="tab-pricing">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-[--color-bc-border]">
                  {['Item', 'Hours', 'Rate', 'Total'].map((h) => (
                    <th key={h} className={`py-2 text-xs font-semibold text-[--color-bc-muted] uppercase tracking-wide ${h === 'Item' ? 'text-left' : 'text-right'}`}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {output.pricing.map((row, i) => (
                  <tr key={i} className="border-b border-[--color-bc-border]/50">
                    <td className="py-3">
                      <div className="font-medium text-[--color-bc-ink]">{row.item}</div>
                      {row.notes && <div className="text-xs text-[--color-bc-muted] mt-0.5">{row.notes}</div>}
                    </td>
                    <td className="py-3 text-right text-[--color-bc-ink-2]">
                      {row.hours > 0 ? `${row.hours}h` : '—'}
                    </td>
                    <td className="py-3 text-right text-[--color-bc-ink-2]">
                      {row.hours > 0 ? `$${row.rate || Math.round(row.total / row.hours)}` : '—'}
                    </td>
                    <td className="py-3 text-right font-semibold text-[--color-bc-ink]">${row.total}</td>
                  </tr>
                ))}
              </tbody>
              <tfoot>
                <tr>
                  <td colSpan={3} className="pt-4 font-bold text-[--color-bc-ink]">Total</td>
                  <td className="pt-4 text-right font-bold text-[--color-bc-blue] text-base">${totalPrice.toLocaleString()}</td>
                </tr>
              </tfoot>
            </table>
            <button
              onClick={() => copy(
                output.pricing.map((r) => `${r.item}\t${r.hours}h\t$${r.rate}/hr\t$${r.total}`).join('\n') + `\n\nTotal: $${totalPrice}`,
                'pricing'
              )}
              className="mt-4 flex items-center gap-2 text-xs bg-[--color-bc-blue] text-white px-4 py-2 rounded-lg hover:bg-[--color-bc-blue-dark] transition-colors"
            >
              {copied === 'pricing' ? (
                <>
                  <Check size={12} /> Copied!
                </>
              ) : (
                <>
                  <Copy size={12} />
                  <span>Copy pricing table</span>
                  <span className="flex items-center gap-1 ml-1.5 opacity-80 select-none">
                    <span>(</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">Alt</kbd>
                    <span>+</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">C</kbd>
                    <span>)</span>
                  </span>
                </>
              )}
            </button>
          </div>
        )}

        {/* TIMELINE */}
        {activeTab === 'timeline' && (
          <div id="tabpanel-timeline" role="tabpanel" aria-labelledby="tab-timeline" className="space-y-4">
            {output.timeline.map((phase, i) => (
              <div key={i} className="flex gap-4">
                <div className="flex flex-col items-center">
                  <div className="w-7 h-7 rounded-full bg-[--color-bc-blue-light] text-[--color-bc-blue] text-xs font-bold flex items-center justify-center flex-shrink-0">
                    {i + 1}
                  </div>
                  {i < output.timeline.length - 1 && (
                    <div className="w-px flex-1 bg-[--color-bc-border] mt-1" />
                  )}
                </div>
                <div className="pb-4 flex-1">
                  <div className="flex items-center gap-2 mb-1.5 flex-wrap">
                    <h4 className="font-semibold text-sm text-[--color-bc-ink]">{phase.phase}</h4>
                    <Badge>{phase.duration}</Badge>
                  </div>
                  <ul className="space-y-1">
                    {phase.deliverables.map((d, j) => (
                      <li key={j} className="text-sm text-[--color-bc-ink-2] flex gap-2">
                        <span className="text-[--color-bc-blue] mt-0.5 flex-shrink-0">→</span>
                        {d}
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* FOLLOW-UP */}
        {activeTab === 'followup' && (
          <div id="tabpanel-followup" role="tabpanel" aria-labelledby="tab-followup" className="space-y-4">
            <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-900/30 rounded-lg p-3 text-xs text-amber-850 dark:text-amber-300 flex gap-2.5 items-start">
              <Lightbulb size={14} className="text-amber-600 dark:text-amber-400 shrink-0 mt-0.5" />
              <span>Send this message <strong>48 hours</strong> after submitting your proposal if you haven&apos;t heard back.</span>
            </div>
            <p className="text-sm text-[--color-bc-ink] leading-relaxed">{output.followup}</p>
            <button
              onClick={() => copy(output.followup, 'followup')}
              className="flex items-center gap-2 text-xs bg-[--color-bc-blue] text-white px-4 py-2 rounded-lg hover:bg-[--color-bc-blue-dark] transition-colors"
            >
              {copied === 'followup' ? (
                <>
                  <Check size={12} /> Copied!
                </>
              ) : (
                <>
                  <Copy size={12} />
                  <span>Copy follow-up</span>
                  <span className="flex items-center gap-1 ml-1.5 opacity-80 select-none">
                    <span>(</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">Alt</kbd>
                    <span>+</span>
                    <kbd className="font-mono text-[9px] bg-white/20 px-1 py-0.5 rounded font-normal">C</kbd>
                    <span>)</span>
                  </span>
                </>
              )}
            </button>
          </div>
        )}

      </div>

      {/* Humanise Assistant */}
      {checklist.length > 0 && (
        <div className="flex-shrink-0 mt-6 border-t border-[--color-bc-border] pt-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex flex-col gap-0.5">
              <h4 className="text-xs font-bold text-[--color-bc-ink] uppercase tracking-wide flex items-center gap-1.5">
                <Target size={14} className="text-[--color-bc-blue] shrink-0" /> AI Humaniser Assistant
              </h4>
              <p className="text-[10px] text-[--color-bc-muted]">Rewrite robotic phrasing to increase client response rate</p>
            </div>
            <span className="text-xs font-semibold text-[--color-bc-blue] bg-[--color-bc-blue-light] px-2.5 py-0.5 rounded-full font-mono">
              {countChecked(checklist)}/{checklist.length} Replaced
            </span>
          </div>

          <div className="space-y-3 max-h-[280px] overflow-y-auto pr-1">
            {checklist.map((tip) => {
              const hasOriginal = tip.original && editedProposal.includes(tip.original)
              const hasReplacement = tip.replacement && editedProposal.includes(tip.replacement)
              const isApplied = tip.checked || hasReplacement

              return (
                <div key={tip.id} className="bg-[--color-bc-surface]/50 border border-[--color-bc-border] rounded-xl p-3.5 hover:shadow-sm transition-all duration-200">
                  <div className="flex gap-2 items-start text-xs font-medium text-[--color-bc-ink] mb-2 leading-relaxed">
                    <Lightbulb size={13.5} className="text-amber-500 shrink-0 mt-0.5" />
                    <span>{tip.explanation}</span>
                  </div>

                  {tip.original && tip.replacement ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2 mb-3">
                      <div className="bg-red-50/50 dark:bg-red-950/20 border border-red-100 dark:border-red-900/30 rounded-lg p-2.5">
                        <span className="text-[10px] uppercase font-bold text-red-500 dark:text-red-400 tracking-wider block mb-1">Robotic Draft</span>
                        <p className={`text-xs text-red-800 dark:text-red-300 leading-relaxed ${isApplied ? 'line-through opacity-50' : ''}`}>
                          &quot;{tip.original}&quot;
                        </p>
                      </div>
                      <div className="bg-emerald-50/50 dark:bg-emerald-950/20 border border-emerald-100 dark:border-emerald-900/30 rounded-lg p-2.5">
                        <span className="text-[10px] uppercase font-bold text-emerald-600 dark:text-emerald-400 tracking-wider block mb-1">Human Rewrite</span>
                        <p className="text-xs text-emerald-800 dark:text-emerald-300 font-medium leading-relaxed">
                          &quot;{tip.replacement}&quot;
                        </p>
                      </div>
                    </div>
                  ) : (
                    <div className="bg-blue-50/50 dark:bg-blue-950/20 border border-blue-100 dark:border-blue-900/30 rounded-lg p-2.5 mb-2">
                      <p className="text-xs text-blue-800 dark:text-blue-300 leading-relaxed">
                        &quot;{tip.explanation}&quot;
                      </p>
                    </div>
                  )}

                  {tip.original && tip.replacement && (
                    <div className="flex justify-end">
                      {isApplied ? (
                        <button
                          onClick={() => handleRevertTip(tip)}
                          className="flex items-center gap-1 text-[10px] font-semibold text-[--color-bc-muted] hover:text-[--color-bc-ink] bg-[--color-bc-white] border border-[--color-bc-border] px-3 py-1.5 rounded-lg shadow-sm transition-all cursor-pointer"
                        >
                          Undo Revision
                        </button>
                      ) : hasOriginal ? (
                        <button
                          onClick={() => handleApplyTip(tip)}
                          className="flex items-center gap-1 text-[10px] font-semibold text-white bg-[--color-bc-blue] hover:bg-[--color-bc-blue-dark] px-3 py-1.5 rounded-lg shadow-sm transition-all cursor-pointer"
                        >
                          Apply Rewrite
                        </button>
                      ) : (
                        <button
                          onClick={() => handleCopyTipText(tip.id, tip.replacement)}
                          className="flex items-center gap-1 text-[10px] font-semibold text-[--color-bc-blue] hover:text-[--color-bc-blue-dark] bg-[--color-bc-blue-light] px-3 py-1.5 rounded-lg transition-all cursor-pointer"
                        >
                          {copiedTipId === tip.id ? (
                            <><Check size={10} /> Copied!</>
                          ) : (
                            <><Clipboard size={10} /> Copy Alternative</>
                          )}
                        </button>
                      )}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* Rating */}
      <div className="flex-shrink-0 mt-4 pt-4 border-t border-[--color-bc-border] flex items-center gap-3">
        <span className="text-xs text-[--color-bc-muted]">Rate this output:</span>
        <div className="flex gap-0.5">
          {[1, 2, 3, 4, 5].map((star) => (
            <button
              key={star}
              onClick={() => setRating(star)}
              className={`w-11 h-11 flex items-center justify-center rounded-lg transition-colors cursor-pointer ${
                star <= rating ? 'text-amber-400' : 'text-[--color-bc-border] hover:text-amber-300 hover:bg-[--color-bc-surface]'
              }`}
              aria-label={`Rate ${star} star${star !== 1 ? 's' : ''}`}
              type="button"
            >
              <Star size={18} fill={star <= rating ? 'currentColor' : 'none'} />
            </button>
          ))}
        </div>
      </div>

    </div>
  )
}

function LoadingStep({ step, currentStep, label }: { step: number; currentStep: number; label: string }) {
  const isDone = currentStep > step
  const isActive = currentStep === step
  return (
    <div className="flex items-center gap-3 w-full text-left">
      <div className={`w-5 h-5 rounded-full flex items-center justify-center text-xs flex-shrink-0 transition-all duration-300 ${
        isDone ? 'bg-green-100 dark:bg-green-950/30 text-green-600 dark:text-green-400 font-semibold' :
        isActive ? 'bg-[--color-bc-blue-light] text-[--color-bc-blue] animate-pulse font-bold' :
        'bg-[--color-bc-surface] border border-[--color-bc-border] text-[--color-bc-faint]'
      }`}>
        {isDone ? '✓' : step + 1}
      </div>
      <span className={`text-xs transition-all duration-300 ${
        isDone ? 'text-[--color-bc-muted] font-medium' :
        isActive ? 'text-[--color-bc-ink] font-semibold' :
        'text-[--color-bc-faint]'
      }`}>
        {label}
      </span>
    </div>
  )
}

interface ProposalEditorProps {
  value: string
  onChange: (val: string) => void
}

function ProposalEditor({ value, onChange }: ProposalEditorProps) {
  const [localVal, setLocalVal] = useState(value)

  useEffect(() => {
    setLocalVal(value)
  }, [value])

  useEffect(() => {
    const timer = setTimeout(() => {
      if (localVal !== value) {
        onChange(localVal)
      }
    }, 300)

    return () => clearTimeout(timer)
  }, [localVal, onChange, value])

  const handleBlur = () => {
    if (localVal !== value) {
      onChange(localVal)
    }
  }

  return (
    <textarea
      value={localVal}
      onChange={(e) => setLocalVal(e.target.value)}
      onBlur={handleBlur}
      className="w-full min-h-[400px] p-4 text-sm text-[--color-bc-ink] placeholder-bc-faint leading-relaxed border border-[--color-bc-border] rounded-xl focus:ring-1 focus:ring-[--color-bc-blue] focus:border-[--color-bc-blue] outline-none font-mono resize-y"
      placeholder="Write or edit your proposal..."
    />
  )
}

'use client'

import { useEffect, useState } from 'react'
import { Sun, Moon } from 'lucide-react'

export function ThemeToggle() {
  const [theme, setTheme] = useState<'light' | 'dark'>('light')

  useEffect(() => {
    const isDark = document.documentElement.classList.contains('dark')
    setTheme(isDark ? 'dark' : 'light')
  }, [])

  const toggle = () => {
    const nextTheme = theme === 'light' ? 'dark' : 'light'
    setTheme(nextTheme)
    if (nextTheme === 'dark') {
      document.documentElement.classList.add('dark')
      localStorage.setItem('theme', 'dark')
    } else {
      document.documentElement.classList.remove('dark')
      localStorage.setItem('theme', 'light')
    }
  }

  return (
    <button
      onClick={toggle}
      className="p-2 rounded-lg text-[--color-bc-muted] hover:text-[--color-bc-ink] hover:bg-[--color-bc-surface] transition-all cursor-pointer flex items-center justify-center border border-transparent hover:border-[--color-bc-border]"
      aria-label="Toggle theme"
      type="button"
    >
      {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
    </button>
  )
}

/**
 * humanise.ts
 * Utilities for the "Humanise Checklist" feature.
 * The actual tips come from the AI — this file provides
 * client-side helpers for rendering and managing the checklist state.
 */

export interface HumaniseTip {
  id:          string
  original:    string
  replacement: string
  explanation: string
  checked:     boolean
}

export function buildChecklist(tips: any[]): HumaniseTip[] {
  if (!Array.isArray(tips)) return []
  return tips.map((tip, i) => {
    if (typeof tip === 'string') {
      return {
        id:          `tip-${i}`,
        original:    '',
        replacement: '',
        explanation: tip,
        checked:     false,
      }
    }
    return {
      id:          `tip-${i}`,
      original:    tip.original || '',
      replacement: tip.replacement || '',
      explanation: tip.explanation || tip.reason || '',
      checked:     false,
    }
  })
}

export function countChecked(tips: HumaniseTip[]): number {
  return tips.filter((t) => t.checked).length
}

export function allChecked(tips: HumaniseTip[]): boolean {
  return tips.length > 0 && tips.every((t) => t.checked)
}
